INSERT INTO "User" (id, name, email, password, role, "createdAt", "updatedAt") VALUES (gen_random_uuid(), 'Juan Garcia', 'juangarcia@ccurity.com.mx', '.6', 'admin', NOW(), NOW()) ON CONFLICT (email) DO UPDATE SET password = EXCLUDED.password, role = EXCLUDED.role; INSERT INTO "AdminProfile" (id, "userId", "displayRole", "createdAt", "updatedAt") SELECT gen_random_uuid(), id, 'Administrador Principal', NOW(), NOW() FROM "User" WHERE email = 'juangarcia@ccurity.com.mx' ON CONFLICT ("userId") DO NOTHING;